"use strict";(globalThis.webpackChunkmavseal=globalThis.webpackChunkmavseal||[]).push([[4482],{6506(e,n,a){a.r(n),a.d(n,{assets:()=>c,contentTitle:()=>o,default:()=>h,frontMatter:()=>i,metadata:()=>t,toc:()=>l});const t=JSON.parse('{"id":"architecture","title":"MavSeal Architecture","description":"MavSeal is an excellent solution for secure and reliable remote signing in Mavryk Blockchain cases. With easy-to-use configuration options, users can set up vaults and policies to ensure that only authorized operations are signed. MavSeal also supports a variety of hardware-based and cloud-based HSMs, such as AWS KMS and YubiHSM, to protect cryptographic keys.","source":"@site/../docs/mavseal-architecture.md","sourceDirName":".","slug":"/architecture","permalink":"/docs/architecture","draft":false,"unlisted":false,"editUrl":"https://github.com/mavryk-network/mavseal/edit/master/website/../docs/mavseal-architecture.md","tags":[],"version":"current","frontMatter":{"id":"architecture","title":"MavSeal Architecture","sidebar_label":"MavSeal Architecture"},"sidebar":"docs","previous":{"title":"Getting Started","permalink":"/docs/start"},"next":{"title":"Mavryk Bakers","permalink":"/docs/bakers"}}');var r=a(4848),s=a(8453);const i={id:"architecture",title:"MavSeal Architecture",sidebar_label:"MavSeal Architecture"},o="MavSeal Architecture",c={},l=[{value:"1. MavSeal System Context",id:"1-mavseal-system-context",level:3},{value:"2. MavSeal Container Model",id:"2-mavseal-container-model",level:3},{value:"3. MavSeal Component Model",id:"3-mavseal-component-model",level:3},{value:"4. Mavryk Signing Component Model",id:"4-mavryk-signing-component-model",level:3},{value:"Simplified Signing Model",id:"simplified-signing-model",level:3}];function d(e){const n={a:"a",h1:"h1",h3:"h3",header:"header",li:"li",mermaid:"mermaid",p:"p",ul:"ul",...(0,s.R)(),...e.components};return(0,r.jsxs)(r.Fragment,{children:[(0,r.jsx)(n.header,{children:(0,r.jsx)(n.h1,{id:"mavseal-architecture",children:"MavSeal Architecture"})}),"\n",(0,r.jsxs)(n.p,{children:["MavSeal is an excellent solution for secure and reliable remote signing in Mavryk Blockchain cases. With easy-to-use configuration options, users can set up vaults and policies to ensure that only authorized operations are signed. MavSeal also supports a variety of hardware-based and cloud-based HSMs, such as ",(0,r.jsx)(n.a,{href:"https://aws.amazon.com/kms/",children:"AWS KMS"})," and ",(0,r.jsx)(n.a,{href:"https://www.yubico.com/",children:"YubiHSM"}),", to protect cryptographic keys."]}),"\n",(0,r.jsx)(n.p,{children:"Using MavSeal, users can securely store their secret keys and control which operations can be signed, reducing the risk of losing or having their keys stolen. MavSeal also allows users to sign transactions on hardware not connected to the internet, providing an additional layer of security."}),"\n",(0,r.jsx)(n.h3,{id:"1-mavseal-system-context",children:"1. MavSeal System Context"}),"\n",(0,r.jsx)(n.p,{children:"The diagram demonstrated the overall high level MavSeal system and includes the MavSeal user, responsible for setting up the system's configuration, and the client software system, which submits requests to the Mavryk API. The diagram also shows various vaults, such as AWS KMS and YubiHSM, which MavSeal uses to store cryptographic keys, and the Prometheus service, which pulls and aggregates metrics data."}),"\n",(0,r.jsx)(n.mermaid,{value:'flowchart TD\nUser["MavSeal User Setup\n[CONFIG]\nBakers or Institutions looking\\n to enforce signing policies"]\n\nS["MavSeal\n[Software System]\nProvides signing options for\\n cloud-based or hardware-based HSMs"]\n\nUser-- "Defines Vault and Policy" --\x3eS\n\nOC["Client\n[Software System]\nsubmits requests to Mavryk API"]\n\nV["Vaults\n[Software Systems]\n AWS KMS, Azure Key Vault, GCP Key Management,\\n YubiHSM, local private key"]\n\nPS["Prometheus Service\n[Software System]\nProvides an API to store and track metrics"]\n\nS-- "Listens for operations" --\x3eOC\nS-- "Remote Signer for" --\x3eV\nS-- "Exposes metric data to" --\x3ePS\n\nclassDef focusSystem fill:#1168bd,stroke:#0b4884,color:#ffffff\nclassDef supportingSystem fill:#666,stroke:#0b4884,color:#ffffff\nclassDef person fill:#08427b,stroke:#052e56,color:#ffffff\nclass User person\nclass S focusSystem\nclass OC,V,PS supportingSystem\n'}),"\n",(0,r.jsx)(n.h3,{id:"2-mavseal-container-model",children:"2. MavSeal Container Model"}),"\n",(0,r.jsx)(n.p,{children:"The MavSeal container diagram shows the different elements of the MavSeal system, including MavSeal as the central container, with various supporting software systems surrounding it. These supporting systems include client software for submitting requests to the Mavryk API, the Prometheus service for storing metrics data, and various hardware-based and cloud-based HSMs for protecting cryptographic keys. The diagram also shows MavSeal's different vaults to store cryptographic keys, such as AWS KMS and YubiHSM."}),"\n",(0,r.jsx)(n.mermaid,{value:'flowchart TD\nUser["MavSeal User\n[Person]\nBaker or Institution operation requests with key security"]\n\nCFG["Configuration File\n[File]\nselect vault, keys and policy"]\n\nOC["Client\n[Software System]\nsubmits requests to Mavryk API"]\n\nP["Software Application\n[PROMETHEUS]\nRecord and store metrics data"]\n\nSL["HTTP Service \n[SIGNING LISTENER]\ncaptures operation signing requests"]\n\nML["HTTP Service \n[METRICS LISTENER]\ncaptures metric data"]\n\nSIG["Service \n[MAVSEAL SERVICE]\ncheck policy and sign"]\n\nY["Hardware Security Module\n[YUBIHSM]\nprotect cryptographic keys"]\n\nL["Hardware Wallet\n[LEDGER]\nstores user\'s private keys"]\n\nLS["File\n[LOCAL-SECRET]\nstores user\'s private keys on disk"]\n\nAWS["Cloud Service \n[AWS]\nblockchain infrastructure"]\n\nG["Cloud Service\n[GOOGLECLOUD]\nblockchain infrastructure"]\n\nA["Cloud Service\n[AZURE]\nblockchain infrastructure"]\n\n\nUser-- "Get Post <br>[HTTP]"--\x3eOC\nUser-- "configures<br>[FILE]"--\x3eCFG\nOC-- "Get Post <br>[HTTP]"--\x3eSL\nML-- "Get<br>[HTTP]" --\x3eP\n\nsubgraph MavSeal[MavSeal]\nSIG--"exposes metrics to<br>[JSON]" --\x3eML\nCFG-- "governs<br>[CODE]"--\x3eSIG\nSL-- "informs<br>[CODE]" --\x3eSIG\nend\n\nSIG-- "sign<br>[USB]" ---\x3eL\nSIG-- "sign<br>[JSON]" ---\x3eLS\nSIG-- "sign<br>[USB]" ---\x3eY\n\nsubgraph Cloud[Cloud]\nSIG-- "sign<br>[HTTP]" ---\x3e AWS\nSIG-- "sign<br>[HTTP]" ---\x3e G\nSIG-- "sign<br>[HTTP]" ---\x3e A\nend\n\n\nclassDef container fill:#1168bd,stroke:#0b4884,color:#ffffff\nclassDef person fill:#08427b,stroke:#052e56,color:#ffffff\nclassDef supportingSystem fill:#666,stroke:#0b4884,color:#ffffff\nclassDef cloud fill:#089319,stroke:#089319,color:#ffffff\nclass User person\nclass SIG,POL,SL,ML,CFG container\nclass C cloud\nclass P,AWS,G,A,L,LS,Y,T,OC supportingSystem'}),"\n",(0,r.jsx)(n.h3,{id:"3-mavseal-component-model",children:"3. MavSeal Component Model"}),"\n",(0,r.jsx)(n.p,{children:"A sequence diagram is a way to express the behaviour of the underlying code in a software system. It shows the interactions between different system components over time, highlighting how the system behaves and responds to different inputs. Using a sequence diagram, developers can better understand the flow of data and control within the system and identify potential issues or areas for improvement."}),"\n",(0,r.jsx)(n.p,{children:"The sequence diagram for the MavSeal remote signer application shows the behaviour of the underlying code in the system. It highlights how the different components of the system interact with one another over time, showing the flow of data and control within the system. Using a sequence diagram, developers can better understand how the system behaves and identify potential issues or areas for improvement."}),"\n",(0,r.jsx)(n.mermaid,{value:"sequenceDiagram\nautonumber\nactor Client\nparticipant MavSeal\nparticipant Signature service\nparticipant Metrics server\nparticipant Vault\n\nMavSeal->>+MavSeal: RootCmd\nMavSeal->>+MavSeal: read config\nMavSeal->>+MavSeal: Register Vaults (Yubikey/Azure/CloudKMS)\nMavSeal->>+MavSeal: Initialize Vault (Yubikey/Azure/CloudKMS)\nMavSeal->>+MavSeal: ServeCmd\n\nMavSeal->>+Signature service: Start service\nMavSeal->>+Metrics server: Start service\n\n\nClient->>+Signature service: GET /authorized_keys \nSignature service->>+Client: Send Authorized keys (Authorised list of clients)\nloop\nClient->>+Signature service: Check the list of configured keys \nend\nalt If Found\nClient->>Signature service: POST /keys/<account> (Signing key)\nClient->>Signature service: Digest string + payload\nSignature service--\x3e>+Client:Show authorized key not found error\nelse Else\nClient--\x3e>+Signature service : continue loop\nend\n\nalt If signing-key found in key-cache\nSignature service->>+Signature service: Return key from cache\nelse Else\nSignature service->>+Vault: GET /public-key\nVault->>+Signature service : Send public key (PEM format)\nSignature service->>+Signature service: Encode secret key into PKH(Public Key Hash)\nSignature service->>+Vault: Request signing operation\nend\n\nVault->>+Signature service : Send Error or Signature\nSignature service->>+Client: Send Error or Signature"}),"\n",(0,r.jsx)(n.h3,{id:"4-mavryk-signing-component-model",children:"4. Mavryk Signing Component Model"}),"\n",(0,r.jsx)(n.p,{children:"Mavryk uses elliptic curve cryptography to manage private/public key pairs, sign data, and check signatures. Signing a transaction involves prefixing it with a magic-byte, hashing the operation request, and then signing the resulting byte string with the user's secret key. The signature is then appended to the operation request to create a signed transaction, which can be broadcast to the network for confirmation."}),"\n",(0,r.jsx)(n.mermaid,{value:'flowchart TB\nTJ["Transfer operation\n[JSON]\nTransaction from Alice to Bob<br>./mavkit-client -l transfer 1 from alice to bob"]\nTN["Mavryk Node\n[Infrastructure]\nhosts RPC service"]\nFT{First<br>Transaction?}\nReveal["Reveal operation\n[Bytes]\nDeclare Public Key "]\nTB["Transaction in Binary\n[Bytes]\na transfer operation request"]\nW["Magic Byte \n[Bytes]\nprefix the request with 0x03"]\nB["Blake2b Hash\n[Bytes]\nhash the operation request"]\nED["Ed25519 Sign\n[Bytes]\nsign the operation request"]\nSK["Secret Key\n[Bytes]\nalice_sk.hex"]\nMAVSEAL["MavSeal Signing Listener\n[HTTP Service]\ncaptures operation signing requests"]\nST["Signed Transaction\n[Bytes]\nsigned hashed prefixed operation\nsignature.hex"]\nTJ --\x3e FT\nFT -- "No<br>operation.kind=transaction<br>Forge RPC" --\x3e TN \nFT -- "Yes" --\x3e Reveal \nReveal -- "operation.kind=reveal<br>Forge RPC" --\x3e FT\nTN-- "Serialize" --\x3eTB\nTB-- "Add" --\x3eW\nW-- "Hash" --\x3eB\nB-- "Send operation.hex" --\x3eED\nSK-- "from vault" --\x3eMAVSEAL\nMAVSEAL-- "Send alice_sk.hex" --\x3eED\nED--"Hash " --\x3eST\nST-- "Injection RPC<br>\n../injection/operation?chain=main<br> --data $(cat operation.hex)$(cat signature.hex)" --\x3eTN\nclassDef node fill:#0C36F1,stroke:#0b4884,color:#ffffff\nclassDef key fill:#F41F38,stroke:#0b4884,color:#ffffff\nclassDef transaction fill:#2591BE,stroke:#0b4884,color:#ffffff\nclassDef signature fill:#F1A40C,stroke:#0b4884,color:#000000\nclass FT,Reveal,TJ,TB,W,B transaction\nclass TN node\nclass SK key\nclass ED,SIG,ST signature'}),"\n",(0,r.jsxs)(n.p,{children:["Diagram adapted from ",(0,r.jsx)(n.a,{href:"https://ocamlpro.com/blog/2018_11_21_an_introduction_to_tezos_rpcs_signing_operations/",children:"An Introduction to Tezos RPCs: Signing Operations"})]}),"\n",(0,r.jsx)(n.h3,{id:"simplified-signing-model",children:"Simplified Signing Model"}),"\n",(0,r.jsx)(n.p,{children:"This Mermaid sequence diagram is a simplified depiction of signing a transaction on the Mavryk blockchain."}),"\n",(0,r.jsxs)(n.ul,{children:["\n",(0,r.jsx)(n.li,{children:"The transaction is first forged using the Mavryk RPC."}),"\n",(0,r.jsx)(n.li,{children:"The resulting operation hexadecimal is then sent to a remote signer for signing."}),"\n",(0,r.jsx)(n.li,{children:"The remote signer receives the operation and the secret key corresponding to the sender's address (in this case, Alice's)."}),"\n",(0,r.jsx)(n.li,{children:"The remote signer signs the transaction and returns the resulting signature hexadecimal."}),"\n",(0,r.jsx)(n.li,{children:"The signed transaction is then sent back to the Mavryk RPC for injection into the blockchain."}),"\n"]}),"\n",(0,r.jsx)(n.mermaid,{value:"sequenceDiagram\n    actor U as User\n    participant OC as Mavkit Client\n    participant TR as Mavryk RPC\n    participant RS as Remote Signer\n    participant V as Vault\n    U->>OC: \n    Note over U, OC : mavkit-client -l transfer 1 from<br>alice to bob \n    OC->>TR: Serialized\n        Note over OC,TR: 0b6b28b6285d1a7146c17dd85f<br>b54b7dc7f68bd7b9a49569ac8f<br>9d6150baa2946c00172d6807f4<br>977e1c67252bdfabbfb37875e3<br>1d4f009dbb0180bd3fe0d403c0<br>843d00001be972fc31a358a26c<br>e970e921e357d95d5abe2400<br>\n    TR->>TR: Add Magic Byte\n            Note over TR: 030b6b28b6285d1a7146c17dd85f<br>b54b7dc7f68bd7b9a49569ac8f<br>9d6150baa2946c00172d6807f4<br>977e1c67252bdfabbfb37875e3<br>1d4f009dbb0180bd3fe0d403c0<br>843d00001be972fc31a358a26c<br>e970e921e357d95d5abe2400<br>\n    TR->>TR: Blake58 Hash\n    V->>RS : alice.hex\n    Note over V, RS: bab4df908ea857e3abecc4<br>0a49e84b4fdc47121b73af<br>461398fc133715199569\n    RS->>RS: signature.hex\n    Note over RS: b965f666f400c1889915a0c6f1a1092cd96c0814d1b<br>bb765678fcf2c86c5079ae1f3735878f8717c230859<br>85c7aa9536fcc9228f42c5d4b6160c2b52a010970b\n    TR->>RS: operation.hex\nRS->>TR: Send to RPC for Injection\n    Note over RS,TR :  'http://127.0.0.1:8732/injection/<br>operation?chain=main' --data '\"'$(<br>cat operation.hex)$(cat signature.hex)'\"'\n    "})]})}function h(e={}){const{wrapper:n}={...(0,s.R)(),...e.components};return n?(0,r.jsx)(n,{...e,children:(0,r.jsx)(d,{...e})}):d(e)}}}]);